DELETE FROM trait_resources tr
USING traits t
WHERE tr.trait_id = t.id
  AND t.name NOT LIKE 'Item:%'
  AND NOT EXISTS (
      SELECT 1
      FROM _import_trait_resource_data data
      WHERE data.trait_name = t.name
        AND data.resource_key = tr.resource_key
  );

INSERT INTO trait_resources (
    trait_id, resource_key, resource_name, count_type, ability, minimum_count,
    pool_multiplier, reset_on, short_rest_recovery, long_rest_recovery, notes
)
SELECT
    t.id, data.resource_key, data.resource_name, data.count_type, data.ability,
    data.minimum_count, data.pool_multiplier, data.reset_on, data.short_rest_recovery,
    data.long_rest_recovery, data.notes
FROM _import_trait_resource_data data
JOIN traits t ON t.name = data.trait_name
ON CONFLICT (trait_id, resource_key) DO UPDATE SET
    resource_name = EXCLUDED.resource_name,
    count_type = EXCLUDED.count_type,
    ability = EXCLUDED.ability,
    minimum_count = EXCLUDED.minimum_count,
    pool_multiplier = EXCLUDED.pool_multiplier,
    reset_on = EXCLUDED.reset_on,
    short_rest_recovery = EXCLUDED.short_rest_recovery,
    long_rest_recovery = EXCLUDED.long_rest_recovery,
    notes = EXCLUDED.notes;

