DELETE FROM trait_resource_progressions trp
USING trait_resources tr, traits t, _import_trait_resource_data data
WHERE trp.trait_resource_id = tr.id
  AND tr.trait_id = t.id
  AND t.name = data.trait_name
  AND tr.resource_key = data.resource_key;

INSERT INTO trait_resource_progressions (
    trait_resource_id, class_level, resource_count, die_value, bonus_value
)
SELECT
    tr.id,
    data.class_level,
    data.resource_count,
    data.die_value,
    data.bonus_value
FROM _import_trait_resource_progression_data data
JOIN traits t ON t.name = data.trait_name
JOIN trait_resources tr ON tr.trait_id = t.id AND tr.resource_key = data.resource_key
ON CONFLICT (trait_resource_id, class_level) DO UPDATE SET
    resource_count = EXCLUDED.resource_count,
    die_value = EXCLUDED.die_value,
    bonus_value = EXCLUDED.bonus_value;

CREATE TEMP TABLE _import_trait_resource_die_data (
    trait_name TEXT NOT NULL,
    die_key TEXT NOT NULL,
    die_name TEXT NOT NULL,
    die_kind TEXT NOT NULL,
    PRIMARY KEY (trait_name, die_key)
) ON COMMIT DROP;

INSERT INTO _import_trait_resource_die_data (trait_name, die_key, die_name, die_kind) VALUES
    ('Bard: Bardic Inspiration', 'bardicInspirationDie', 'Bardic Inspiration Die', 'die'),
    ('Barbarian: Rage', 'rageDamage', 'Rage Damage Bonus', 'bonus'),
    ('Monk: Martial Arts', 'martialArtsDie', 'Martial Arts Die', 'die'),
    ('Ranger: Favored Enemy', 'huntersMarkDamage', 'Hunter''s Mark Damage Die', 'die');

INSERT INTO trait_resource_dice (trait_id, die_key, die_name, die_kind)
SELECT t.id, data.die_key, data.die_name, data.die_kind
FROM _import_trait_resource_die_data data
JOIN traits t ON t.name = data.trait_name
ON CONFLICT (trait_id, die_key) DO UPDATE SET
    die_name = EXCLUDED.die_name,
    die_kind = EXCLUDED.die_kind;

CREATE TEMP TABLE _import_trait_resource_die_progression_data (
    trait_name TEXT NOT NULL,
    die_key TEXT NOT NULL,
    class_level INT NOT NULL,
    die_value TEXT NOT NULL,
    PRIMARY KEY (trait_name, die_key, class_level)
) ON COMMIT DROP;

