DELETE FROM trait_resource_die_progressions trdp
USING trait_resource_dice trd, traits t, _import_trait_resource_die_data data
WHERE trdp.trait_resource_die_id = trd.id
  AND trd.trait_id = t.id
  AND t.name = data.trait_name
  AND trd.die_key = data.die_key;

INSERT INTO trait_resource_die_progressions (trait_resource_die_id, class_level, die_value)
SELECT trd.id, data.class_level, data.die_value
FROM _import_trait_resource_die_progression_data data
JOIN traits t ON t.name = data.trait_name
JOIN trait_resource_dice trd ON trd.trait_id = t.id AND trd.die_key = data.die_key
ON CONFLICT (trait_resource_die_id, class_level) DO UPDATE SET
    die_value = EXCLUDED.die_value;

COMMIT;
